def test_tuesday_2pm_pacific_rejects_am_selection():
    page = FakeBookingPage(selected={
        "date": "2026-06-23",
        "time": "02:00",
        "time_display": "2:00 AM",
        "timezone": "America/Los_Angeles",
    }, warnings=["This is an early-morning slot (2:00 AM). Did you mean 2:00 PM?"])
    goal = "Book a demo for next Tuesday at 2pm Pacific."
    with pytest.raises(CompletionError):
        complete_task(page, goal, "booked")


def test_tuesday_2pm_pacific_accepts_pm_selection():
    page = FakeBookingPage(selected={
        "date": "2026-06-23",
        "time": "14:00",
        "time_display": "2:00 PM",
        "timezone": "America/Los_Angeles",
    }, warnings=[])
    goal = "Book a demo for next Tuesday at 2pm Pacific."
    assert complete_task(page, goal, "booked") == "booked"
